package il.co.dcd.composermapper.index; import java.nio.file.*; import java.io.IOException;
public class IniMappingIndexer { public void index(Path ini, Indexes x){ try{ for(String raw:Files.readAllLines(ini)){ String line=raw.trim(); if(line.isEmpty()||line.startsWith("#")||line.startsWith(";")||line.startsWith("[")) continue; int i=line.indexOf('='); if(i<=0||i>=line.length()-1) continue; String tag=line.substring(0,i).trim(); String fqcn=line.substring(i+1).trim(); if(!tag.isBlank()&&!fqcn.isBlank()){ x.tagToClass().put(tag,fqcn); x.tagToSource().put(tag,ini); } } }catch(IOException e){ throw new RuntimeException("Failed parsing INI: "+ini,e);} } }
